#include <bits/stdc++.h>
using namespace std;

int n,m,k[10],p[10];
long long ans;
map<int,int> mp;

int qpow(int a,int b){
    int ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base;
        base=base*base,b>>=1;
    }
    return ans;
}

void dfs1(int x,int sum){
    if(x>n/2){
        mp[sum]++;
        return;
    }
    for(int i=1;i<=m;i++)
        dfs1(x+1,sum+k[x]*qpow(i,p[x]));
}

void dfs2(int x,int sum){
    if(x>n){
        ans+=mp[sum];
        return;
    }
    for(int i=1;i<=m;i++)
        dfs2(x+1,sum-k[x]*qpow(i,p[x]));
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&k[i],&p[i]);
    dfs1(1,0);
    dfs2(n/2+1,0);
    printf("%lld",ans);
    return 0;
}
